  1→#![windows_subsystem = "windows"]
  2→
  3→use chrono::{Local, NaiveTime};
  4→use std::env;
  5→use std::ffi::c_void;
  6→use std::fs::{self, File, OpenOptions};
  7→use std::io::{Read, Seek, SeekFrom, Write};
  8→use std::path::PathBuf;
  9→use std::process::Command;
 10→use std::sync::Mutex;
 11→use std::thread;
 12→use std::time::Duration;
 13→use sysinfo::System;
 14→
 15→// --- Constants (matching C# version) ---
 16→const MONITOR_INTERVAL_SECONDS: u64 = 10;
 17→const STATUS_TIMEOUT_SECONDS: u64 = 5;
 18→const START_TIMEOUT_SECONDS: u64 = 10;
 19→const RECOVERY_RETRY_COUNT: u32 = 3;
 20→const EXPECTED_ESPANSO_PROCESS_COUNT: usize = 3;
 21→const ESPANSO_LOG_TAIL_BYTES: u64 = 256 * 1024;
 22→const MAX_LOG_FILE_BYTES: u64 = 2 * 1024 * 1024;
 23→const CRITICAL_LOG_LOOKBACK_MINUTES: i64 = 2;
 24→const RECOVERY_KILL_WAIT: Duration = Duration::from_secs(1);
 25→const RECOVERY_START_WAIT: Duration = Duration::from_secs(2);
 26→
 27→static LOG_LOCK: Mutex<()> = Mutex::new(());
 28→
 29→// --- Windows FFI ---
 30→#[allow(clippy::upper_case_acronyms)]
 31→type HANDLE = *mut c_void;
 32→#[allow(clippy::upper_case_acronyms)]
 33→type BOOL = i32;
 34→#[allow(clippy::upper_case_acronyms)]
 35→type DWORD = u32;
 36→#[allow(clippy::upper_case_acronyms)]
 37→type LPCWSTR = *const u16;
 38→
 39→const WAIT_OBJECT_0: DWORD = 0;
 40→const WAIT_ABANDONED: DWORD = 0x00000080;
 41→const PROCESS_SET_INFORMATION: DWORD = 0x0200;
 42→const HIGH_PRIORITY_CLASS: DWORD = 0x00000080;
 43→
 44→extern "system" {
 45→    fn CreateMutexW(
 46→        lpMutexAttributes: *const c_void,
 47→        bInitialOwner: BOOL,
 48→        lpName: LPCWSTR,
 49→    ) -> HANDLE;
 50→    fn WaitForSingleObject(hHandle: HANDLE, dwMilliseconds: DWORD) -> DWORD;
 51→    fn ReleaseMutex(hMutex: HANDLE) -> BOOL;
 52→    fn CloseHandle(hObject: HANDLE) -> BOOL;
 53→    fn OpenProcess(dwDesiredAccess: DWORD, bInheritHandle: BOOL, dwProcessId: DWORD) -> HANDLE;
 54→    fn SetPriorityClass(hProcess: HANDLE, dwPriorityClass: DWORD) -> BOOL;
 55→}
 56→
 57→// --- Named Mutex RAII wrapper ---
 58→struct WinMutex {
 59→    handle: HANDLE,
 60→}
 61→
 62→unsafe impl Send for WinMutex {}
 63→
 64→impl WinMutex {
 65→    fn try_acquire(name: &str) -> Option<Self> {
 66→        let wide: Vec<u16> = name.encode_utf16().chain(std::iter::once(0)).collect();
 67→        let handle = unsafe { CreateMutexW(std::ptr::null(), 0, wide.as_ptr()) };
 68→        if handle.is_null() {
 69→            return None;
 70→        }
 71→        // Always try to acquire ownership (matches C# mutex.WaitOne(0))
 72→        let wait = unsafe { WaitForSingleObject(handle, 0) };
 73→        if wait != WAIT_OBJECT_0 && wait != WAIT_ABANDONED {
 74→            unsafe { CloseHandle(handle) };
 75→            return None;
 76→        }
 77→        Some(WinMutex { handle })
 78→    }
 79→}
 80→
 81→impl Drop for WinMutex {
 82→    fn drop(&mut self) {
 83→        unsafe {
 84→            ReleaseMutex(self.handle);
 85→            CloseHandle(self.handle);
 86→        }
 87→    }
 88→}
 89→
 90→// --- Command result ---
 91→struct CommandResult {
 92→    completed: bool,
 93→    timed_out: bool,
 94→    exit_code: Option<i32>,
 95→    stdout: String,
 96→    stderr: String,
 97→    error_message: String,
 98→}
 99→
100→impl CommandResult {
101→    fn failed(message: String) -> Self {
102→        Self {
103→            completed: false,
104→            timed_out: false,
105→            exit_code: None,
106→            stdout: String::new(),
107→            stderr: String::new(),
108→            error_message: message,
109→        }
110→    }
111→
112→    fn timed_out_result(stdout: String, stderr: String) -> Self {
113→        Self {
114→            completed: false,
115→            timed_out: true,
116→            exit_code: None,
117→            stdout,
118→            stderr,
119→            error_message: String::new(),
120→        }
121→    }
122→
123→    fn completed_result(exit_code: i32, stdout: String, stderr: String) -> Self {
124→        Self {
125→            completed: true,
126→            timed_out: false,
127→            exit_code: Some(exit_code),
128→            stdout,
129→            stderr,
130→            error_message: String::new(),
131→        }
132→    }
133→}
134→
135→// --- Paths ---
136→fn app_dir() -> PathBuf {
137→    let local_app_data = env::var("LOCALAPPDATA").unwrap_or_else(|_| ".".to_string());
138→    PathBuf::from(&local_app_data).join("EspansoWatchdog")
139→}
140→
141→fn log_path() -> PathBuf {
142→    app_dir().join("watchdog.log")
143→}
144→
145→fn espanso_log_path() -> PathBuf {
146→    let local_app_data = env::var("LOCALAPPDATA").unwrap_or_else(|_| ".".to_string());
147→    PathBuf::from(&local_app_data)
148→        .join("espanso")
149→        .join("espanso.log")
150→}
151→
152→fn resolve_espanso_cli_path() -> String {
153→    let local_app_data = env::var("LOCALAPPDATA").unwrap_or_else(|_| ".".to_string());
154→    let local_programs = PathBuf::from(&local_app_data)
155→        .join("Programs")
156→        .join("Espanso");
157→
158→    let espansod = local_programs.join("espansod.exe");
159→    if espansod.exists() {
160→        return espansod.to_string_lossy().to_string();
161→    }
162→
163→    let espanso = local_programs.join("espanso.exe");
164→    if espanso.exists() {
165→        return espanso.to_string_lossy().to_string();
166→    }
167→
168→    "espanso".to_string()
169→}
170→
171→// --- Logging ---
172→fn log(message: &str) {
173→    let line = format!("{} {}", Local::now().format("%Y-%m-%d %H:%M:%S"), message);
174→    let _lock = LOG_LOCK.lock().unwrap_or_else(|e| e.into_inner());
175→
176→    let log = log_path();
177→
178→    // Log rotation
179→    if let Ok(meta) = fs::metadata(&log) {
180→        if meta.len() > MAX_LOG_FILE_BYTES {
181→            let backup = log.with_extension("log.old");
182→            let _ = fs::remove_file(&backup);
183→            let _ = fs::rename(&log, &backup);
184→        }
185→    }
186→
187→    if let Ok(mut f) = OpenOptions::new().create(true).append(true).open(&log) {
188→        let _ = writeln!(f, "{}", line);
189→    }
190→}
191→
192→// --- Trim helper ---
193→fn trim_for_log(text: &str, max_length: usize) -> String {
194→    let trimmed = text.trim();
195→    if trimmed.is_empty() {
196→        return String::new();
197→    }
198→    let single_line: String = trimmed.replace(['\r', '\n'], " ");
199→    if single_line.len() <= max_length {
200→        single_line
201→    } else {
202→        let mut end = max_length;
203→        while !single_line.is_char_boundary(end) && end > 0 {
204→            end -= 1;
205→        }
206→        format!("{}...", &single_line[..end])
207→    }
208→}
209→
210→// Kill a process and all its descendants (process tree).
211→fn kill_process_tree(pid: u32) {
212→    use std::os::windows::process::CommandExt;
213→    const CREATE_NO_WINDOW: u32 = 0x08000000;
214→    let _ = Command::new("taskkill")
215→        .args(["/F", "/T", "/PID", &pid.to_string()])
216→        .creation_flags(CREATE_NO_WINDOW)
217→        .stdout(std::process::Stdio::null())
218→        .stderr(std::process::Stdio::null())
219→        .status();
220→}
221→
222→// --- Run command with timeout ---
223→fn run_command(file_name: &str, arguments: &str, timeout: Duration) -> CommandResult {
224→    use std::os::windows::process::CommandExt;
225→    use std::sync::mpsc;
226→    const CREATE_NO_WINDOW: u32 = 0x08000000;
227→
228→    let args: Vec<&str> = arguments.split_whitespace().collect();
229→    let child = Command::new(file_name)
230→        .args(&args)
231→        .stdout(std::process::Stdio::piped())
232→        .stderr(std::process::Stdio::piped())
233→        .creation_flags(CREATE_NO_WINDOW)
234→        .spawn();
235→
236→    let mut child = match child {
237→        Ok(c) => c,
238→        Err(e) => return CommandResult::failed(e.to_string()),
239→    };
240→
241→    let child_pid = child.id();
242→
243→    // Read stdout/stderr in background threads to avoid pipe buffer deadlock.
244→    // Use channels so we can collect output with a timeout (child processes
245→    // may inherit pipe handles and keep them open after the parent exits).
246→    let (stdout_tx, stdout_rx) = mpsc::channel();
247→    let (stderr_tx, stderr_rx) = mpsc::channel();
248→
249→    if let Some(out) = child.stdout.take() {
250→        thread::spawn(move || {
251→            let mut s = String::new();
252→            let mut out = out;
253→            let _ = out.read_to_string(&mut s);
254→            let _ = stdout_tx.send(s);
255→        });
256→    }
257→    if let Some(err) = child.stderr.take() {
258→        thread::spawn(move || {
259→            let mut s = String::new();
260→            let mut err = err;
261→            let _ = err.read_to_string(&mut s);
262→            let _ = stderr_tx.send(s);
263→        });
264→    }
265→
266→    let start = std::time::Instant::now();
267→    loop {
268→        match child.try_wait() {
269→            Ok(Some(status)) => {
270→                // Process exited. Give reader threads 2s to finish
271→                // (child processes may keep pipes open longer).
272→                let stdout = stdout_rx
273→                    .recv_timeout(Duration::from_secs(2))
274→                    .unwrap_or_default();
275→                let stderr = stderr_rx
276→                    .recv_timeout(Duration::from_secs(2))
277→                    .unwrap_or_default();
278→                return CommandResult::completed_result(
279→                    status.code().unwrap_or(-1),
280→                    stdout.trim().to_string(),
281→                    stderr.trim().to_string(),
282→                );
283→            }
284→            Ok(None) => {
285→                if start.elapsed() >= timeout {
286→                    // Kill entire process tree so grandchildren that inherited
287→                    // pipe handles are also terminated, preventing thread leaks.
288→                    kill_process_tree(child_pid);
289→                    let _ = child.wait();
290→                    let stdout = stdout_rx
291→                        .recv_timeout(Duration::from_secs(2))
292→                        .unwrap_or_default();
293→                    let stderr = stderr_rx
294→                        .recv_timeout(Duration::from_secs(2))
295→                        .unwrap_or_default();
296→                    return CommandResult::timed_out_result(
297→                        stdout.trim().to_string(),
298→                        stderr.trim().to_string(),
299→                    );
300→                }
301→                thread::sleep(Duration::from_millis(100));
302→            }
303→            Err(e) => return CommandResult::failed(e.to_string()),
304→        }
305→    }
306→}
307→
308→fn format_command_result(result: &CommandResult) -> String {
309→    let out_text = trim_for_log(&result.stdout, 160);
310→    let err_text = trim_for_log(&result.stderr, 160);
311→    let msg_text = trim_for_log(&result.error_message, 160);
312→    let exit_str = match result.exit_code {
313→        Some(code) => code.to_string(),
314→        None => "null".to_string(),
315→    };
316→    format!(
317→        "completed={}, timedOut={}, exitCode={}, stdout=\"{}\", stderr=\"{}\", error=\"{}\"",
318→        result.completed, result.timed_out, exit_str, out_text, err_text, msg_text
319→    )
320→}
321→
322→// --- Process management ---
323→fn is_espanso_process(process: &sysinfo::Process) -> bool {
324→    let name = process.name().to_string_lossy().to_lowercase();
325→    name == "espanso" || name == "espanso.exe" || name == "espansod" || name == "espansod.exe"
326→}
327→
328→fn get_espanso_process_count(sys: &mut System) -> usize {
329→    sys.refresh_processes(sysinfo::ProcessesToUpdate::All, true);
330→    sys.processes()
331→        .values()
332→        .filter(|p| is_espanso_process(p))
333→        .count()
334→}
335→
336→fn kill_espanso_processes(sys: &mut System) -> u32 {
337→    sys.refresh_processes(sysinfo::ProcessesToUpdate::All, true);
338→    let mut killed = 0u32;
339→    let pids: Vec<sysinfo::Pid> = sys
340→        .processes()
341→        .iter()
342→        .filter(|(_, p)| is_espanso_process(p))
343→        .map(|(pid, _)| *pid)
344→        .collect();
345→
346→    for pid in pids {
347→        if let Some(process) = sys.process(pid) {
348→            if process.kill() {
349→                killed += 1;
350→            } else {
351→                log(&format!("failed to kill pid={}", pid));
352→            }
353→        }
354→    }
355→    killed
356→}
357→
358→fn set_espanso_high_priority(sys: &mut System) -> u32 {
359→    sys.refresh_processes(sysinfo::ProcessesToUpdate::All, true);
360→    let mut count = 0u32;
361→    for (pid, process) in sys.processes() {
362→        if !is_espanso_process(process) {
363→            continue;
364→        }
365→        let raw_pid = pid.as_u32();
366→        let handle = unsafe { OpenProcess(PROCESS_SET_INFORMATION, 0, raw_pid) };
367→        if handle.is_null() {
368→            continue;
369→        }
370→        let ok = unsafe { SetPriorityClass(handle, HIGH_PRIORITY_CLASS) };
371→        unsafe { CloseHandle(handle) };
372→        if ok != 0 {
373→            count += 1;
374→        }
375→    }
376→    count
377→}
378→
379→// --- Espanso log analysis ---
380→fn read_tail_text(path: &PathBuf, max_bytes: u64) -> Result<String, std::io::Error> {
381→    let mut file = File::open(path)?;
382→    let length = file.metadata()?.len();
383→    let bytes_to_read = length.min(max_bytes);
384→    if bytes_to_read == 0 {
385→        return Ok(String::new());
386→    }
387→
388→    file.seek(SeekFrom::End(-(bytes_to_read as i64)))?;
389→    let mut buffer = vec![0u8; bytes_to_read as usize];
390→    let read = file.read(&mut buffer)?;
391→    let mut text = String::from_utf8_lossy(&buffer[..read]).to_string();
392→
393→    if length > max_bytes {
394→        if let Some(pos) = text.find('\n') {
395→            if pos + 1 < text.len() {
396→                text = text[pos + 1..].to_string();
397→            }
398→        }
399→    }
400→
401→    Ok(text)
402→}
403→
404→fn is_recent_espanso_log_line(line: &str) -> bool {
405→    if line.len() < 8 || !line.is_char_boundary(8) {
406→        return false;
407→    }
408→
409→    let time_str = &line[..8];
410→    let parsed_time = match NaiveTime::parse_from_str(time_str, "%H:%M:%S") {
411→        Ok(t) => t,
412→        Err(_) => return false,
413→    };
414→
415→    let now = Local::now();
416→    let today = now.date_naive();
417→    let mut line_dt = today
418→        .and_time(parsed_time)
419→        .and_local_timezone(Local)
420→        .single();
421→
422→    if let Some(dt) = line_dt {
423→        if dt > now + chrono::Duration::minutes(1) {
424→            line_dt = (today - chrono::Duration::days(1))
425→                .and_time(parsed_time)
426→                .and_local_timezone(Local)
427→                .single();
428→        }
429→    }
430→
431→    match line_dt {
432→        Some(dt) => {
433→            let diff = now.signed_duration_since(dt);
434→            diff >= chrono::Duration::zero()
435→                && diff <= chrono::Duration::minutes(CRITICAL_LOG_LOOKBACK_MINUTES)
436→        }
437→        None => false,
438→    }
439→}
440→
441→fn is_critical_espanso_log_line(line: &str) -> bool {
442→    let lower = line.to_lowercase();
443→    lower.contains("[error]")
444→        && lower.contains("could not restart worker")
445→        && is_recent_espanso_log_line(line)
446→}
447→
448→fn get_latest_critical_espanso_log_line() -> Option<String> {
449→    let path = espanso_log_path();
450→    if !path.exists() {
451→        return None;
452→    }
453→
454→    let tail = match read_tail_text(&path, ESPANSO_LOG_TAIL_BYTES) {
455→        Ok(t) => t,
456→        Err(e) => {
457→            log(&format!(
458→                "failed to read espanso.log: {}",
459→                trim_for_log(&e.to_string(), 200)
460→            ));
461→            return None;
462→        }
463→    };
464→
465→    let lines: Vec<&str> = tail.split(['\r', '\n']).filter(|l| !l.is_empty()).collect();
466→
467→    for line in lines.iter().rev() {
468→        if is_critical_espanso_log_line(line) {
469→            return Some(trim_for_log(line, 220));
470→        }
471→    }
472→
473→    None
474→}
475→
476→// --- Health check ---
477→struct HealthState {
478→    last_critical_log_line: Option<String>,
479→    sys: System,
480→    espanso_cli: String,
481→}
482→
483→impl HealthState {
484→    fn new() -> Self {
485→        Self {
486→            last_critical_log_line: None,
487→            sys: System::new(),
488→            espanso_cli: resolve_espanso_cli_path(),
489→        }
490→    }
491→
492→    fn is_healthy(&mut self) -> (bool, String) {
493→        let status_result = run_command(
494→            &self.espanso_cli,
495→            "service status",
496→            Duration::from_secs(STATUS_TIMEOUT_SECONDS),
497→        );
498→
499→        let service_running = status_result.completed
500→            && status_result
501→                .stdout
502→                .to_lowercase()
503→                .contains("espanso is running");
504→
505→        let process_count = get_espanso_process_count(&mut self.sys);
506→        let has_required = process_count >= EXPECTED_ESPANSO_PROCESS_COUNT;
507→        let basic_healthy = service_running && has_required;
508→
509→        if basic_healthy {
510→            if let Some(critical_line) = get_latest_critical_espanso_log_line() {
511→                let is_new = self.last_critical_log_line.as_ref() != Some(&critical_line);
512→                if is_new {
513→                    self.last_critical_log_line = Some(critical_line.clone());
514→                    let detail = format!(
515→                        "criticalEspansoError=\"{}\", serviceRunning={}, processCount={}, status={}",
516→                        critical_line,
517→                        service_running,
518→                        process_count,
519→                        format_command_result(&status_result)
520→                    );
521→                    return (false, detail);
522→                }
523→            }
524→        }
525→
526→        let detail = format!(
527→            "serviceRunning={}, processCount={}, status={}",
528→            service_running,
529→            process_count,
530→            format_command_result(&status_result)
531→        );
532→        (basic_healthy, detail)
533→    }
534→
535→    fn ensure_healthy(&mut self) -> bool {
536→        let (healthy, detail) = self.is_healthy();
537→        if healthy {
538→            let priority_count = set_espanso_high_priority(&mut self.sys);
539→            log(&format!(
540→                "healthy: {} (priority set on {} processes)",
541→                detail, priority_count
542→            ));
543→            return true;
544→        }
545→
546→        log(&format!("unhealthy detected: {}", detail));
547→
548→        for attempt in 1..=RECOVERY_RETRY_COUNT {
549→            let killed = kill_espanso_processes(&mut self.sys);
550→            log(&format!(
551→                "recovery attempt {}/{}: killed espanso processes={}.",
552→                attempt, RECOVERY_RETRY_COUNT, killed
553→            ));
554→
555→            thread::sleep(RECOVERY_KILL_WAIT);
556→
557→            let start_result = run_command(
558→                &self.espanso_cli,
559→                "service start --unmanaged",
560→                Duration::from_secs(START_TIMEOUT_SECONDS),
561→            );
562→
563→            log(&format!(
564→                "recovery attempt {}/{}: service start result={}.",
565→                attempt,
566→                RECOVERY_RETRY_COUNT,
567→                format_command_result(&start_result)
568→            ));
569→
570→            thread::sleep(RECOVERY_START_WAIT);
